+      file: path.relative(args.cwd, file),
+      title: data.title,
+      type: data.type,
+      date_occurred: data.date_occurred,
+      status: data.status,
+      days_apart: dateDistance,
+      similarity: Number(score.toFixed(3)),
+    });
+  }
+  return candidates.sort((a, b) => b.similarity - a.similarity || a.days_apart - b.days_apart);
+}
