    date_collected: "2026-07-03",
    market: "US",
    affected_concerns: ["pigmentation", "sensitive_soothing"],
    affected_channels: ["amazon"],
    summary: "레티날 스킨부스터 세럼이 Amazon 페이셜 세럼 관련 랭킹에서 성과를 보였다는 보도",
    sources: [{ url: "https://m.segyebiz.com/newsView/20250630512900", tier: "press", title: "글로벌 판매량 증가 보도" }],
    status: "unreviewed",
