}

function dump(data) {
  return yaml.dump(data, { lineWidth: -1, noRefs: true, sortKeys: false });
}

function readYaml(file) {
  return yaml.load(fs.readFileSync(file, "utf8"), { schema: yaml.JSON_SCHEMA });
